const Joi = require('joi');
const { ValidationError } = require('../errors');

function formatJoiErrors(details) {
  return details.map(d => ({ field: d.path.join('.'), message: d.message.replace(/"/g, '') }));
}

/**
 * validation middleware factory
 * schema: { body?: Joi.Schema, params?: Joi.Schema, query?: Joi.Schema }
 */
function validate(schema = {}) {
  return (req, res, next) => {
    try {
      const allErrors = [];

      if (schema.params) {
        const { value, error } = schema.params.validate(req.params, { abortEarly: false, allowUnknown: false, convert: true });
        if (error) allErrors.push(...error.details);
        else req.params = value;
      }

      if (schema.query) {
        const { value, error } = schema.query.validate(req.query, { abortEarly: false, allowUnknown: false, convert: true });
        if (error) allErrors.push(...error.details);
        else req.query = value;
      }

      if (schema.body) {
        const { value, error } = schema.body.validate(req.body, { abortEarly: false, allowUnknown: false, convert: true });
        if (error) allErrors.push(...error.details);
        else req.body = value;
      }

      if (allErrors.length > 0) {
        const details = formatJoiErrors(allErrors);
        throw new ValidationError('Request validation failed', { details });
      }

      next();
    } catch (err) {
      next(err);
    }
  };
}

module.exports = validate;

const express = require('express');
const authService = require('../services/auth.service');
const authMiddleware = require('../middlewares/auth.middleware');
const validate = require('../middlewares/validate.middleware');
const Joi = require('joi');

const router = express.Router();

const registerSchema = Joi.object({
	email: Joi.string().email().required(),
	password: Joi.string().min(8).required(),
});

router.post('/auth/register', validate({ body: registerSchema }), async (req, res, next) => {
	try {
		const created = await authService.register(req.body);
		res.status(201).json(created);
	} catch (err) {
		next(err);
	}
});

router.post('/auth/login', async (req, res, next) => {
	try {
		const resp = await authService.login(req.body);
		res.json(resp);
	} catch (err) {
		next(err);
	}
});

router.post('/auth/logout', authMiddleware.authenticateRequired, async (req, res, next) => {
	try {
		// Stateless JWT: nothing to do server-side for basic logout
		res.status(204).end();
	} catch (err) {
		next(err);
	}
});

router.get('/auth/me', authMiddleware.authenticateRequired, async (req, res, next) => {
	try {
		// auth middleware attaches `req.user`
		res.json(req.user);
	} catch (err) {
		next(err);
	}
});

module.exports = router;

